1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	const LOYALTY_DISCOUNT_RATE = 0.2;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const CURSED_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const PROCESSING_FEE = 5;
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_BASE = 60;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const CAP_MULTIPLIER = 2;
32	const DEDUCTIBLE = 100;
33	
34	const baseForType = (type: string, count: number): number => {
35	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
36	    return COMPONENT_BLOCK_BASE;
37	  }
38	  return count * BASE_PREMIUMS[type];
39	};
40	
41	export const runScenario = (scenario: any): unknown => {
42	  const results = [];
43	  let quoteStepsSeen = 0;
44	  const policiesByStepIndex = new Map<number, { capRemaining: number }>();
45	  for (let stepIndex = 0; stepIndex < scenario.steps.length; stepIndex++) {
46	    const step = scenario.steps[stepIndex];
47	    if (step.op === "claim") {
48	      const policy = policiesByStepIndex.get(step.policy)!;
49	      const damage = step.incident.damages[0];
50	      const payout = Math.max(0, damage.amount - DEDUCTIBLE);
51	      policy.capRemaining -= payout;
52	      results.push({ payout, remainingCap: policy.capRemaining });
53	      continue;
54	    }
55	    const items = step.items;
56	    const countsByType = new Map<string, number>();
57	    for (const item of items) {
58	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
59	    }
60	    let itemBasesSum = 0;
61	    for (const [type, count] of countsByType) {
62	      itemBasesSum += baseForType(type, count);
63	    }
64	    let itemSurcharges = 0;
65	    let insuranceSum = 0;
66	    for (const item of items) {
67	      const itemBase = BASE_PREMIUMS[item.type];
68	      if (item.cursed) {
69	        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
70	      }
71	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
72	        itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
73	      }
74	      insuranceSum += INSURANCE_VALUES[item.type];
75	    }
76	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
77	      ? itemBasesSum * LOYALTY_DISCOUNT_RATE
78	      : 0;
79	    const followUpDiscount = quoteStepsSeen > 0
80	      ? itemBasesSum * FOLLOW_UP_DISCOUNT_RATE
81	      : 0;
82	    const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount + itemSurcharges;
83	    const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
84	    results.push({ premium });
85	    policiesByStepIndex.set(stepIndex, { capRemaining: insuranceSum * CAP_MULTIPLIER });
86	    quoteStepsSeen++;
87	  }
88	  return { results };
89	};
