input.new_string:
const policiesByStepIndex = new Map<number, { capRemaining: number; items: any[] }>();
for (let stepIndex = 0; stepIndex < scenario.steps.length; stepIndex++) {
  const step = scenario.steps[stepIndex];
  if (step.op === "claim") {
    const policy = policiesByStepIndex.get(step.policy)!;
    const damage = step.incident.damages[0];
    const insuredItem = policy.items.find((i: any) => i.type === damage.itemType);
    let base = damage.amount;
    if (insuredItem && insuredItem.enchantment >= 8) {
      base = base * 0.5;
    } else if (insuredItem && insuredItem.material === "dragon") {
      base = base;
    }
    const payout = Math.max(0, base - DEDUCTIBLE);
    policy.capRemaining -= payout;
    results.push({ payout, remainingCap: policy.capRemaining });
    continue;
  }
